#include<bits/stdc++.h>
using namespace std;
void init(vector<int> H);
long long query(int S, int E);
long long a[500010],sum[500010],n;
struct node
{
	long long id,p;
}nxt[500010][21],pre[500010][21];
void init(vector<int> H)
{
	n=H.size();
	for(long long i=1;i<=n;i++)
	{
		a[i]=H[i-1];
		sum[i]=sum[i-1]+a[i];
	}
	for(long long i=0;i<=20;i++)
	{
		nxt[n+1][i]=(node){n+1,0};
	}
	stack<long long> s;
	for(long long i=n;i>=1;i--)
	{
		while(!s.empty()&&a[s.top()]<a[i])
		{
			s.pop();
		}
		if(!s.empty())
		{
			nxt[i][0]=(node){s.top(),(s.top()-i-1)*a[i]+sum[i]-sum[s.top()-1]};
		}
		else
		{
			nxt[i][0]=(node){n+1,0};
		}
		s.push(i);
	}
	while(!s.empty())
	{
		s.pop();
	}
	for(long long i=1;i<=n;i++)
	{
		while(!s.empty()&&a[s.top()]<a[i])
		{
			s.pop();
		}
		if(!s.empty())
		{
			pre[i][0]=(node){s.top(),(i-s.top())*a[i]-sum[i]+sum[s.top()]};
		}
		else
		{
			pre[i][0]=(node){0,0};
		}
		s.push(i);
	}
	for(long long i=1;i<=20;i++)
	{
		for(long long j=1;j<=n;j++)
		{
			nxt[j][i].id=nxt[nxt[j][i-1].id][i-1].id;
			nxt[j][i].p=nxt[j][i-1].p+nxt[nxt[j][i-1].id][i-1].p;
			pre[j][i].id=pre[pre[j][i-1].id][i-1].id;
			pre[j][i].p=pre[j][i-1].p+pre[pre[j][i-1].id][i-1].p;
		}
	}
}
long long query(int S,int E)
{
	int l=S,r=E;
	long long x=l;
	long long ans=0;
	for(long long i=20;i>=0;i--)
	{
		if(nxt[x][i].id<=r)
		{
			ans+=nxt[x][i].p;
			x=nxt[x][i].id;
		}
	}
	long long pos=x;
	x=r;
	for(long long i=20;i>=0;i--)
	{
		if(pre[x][i].id>=pos)
		{
			ans+=pre[x][i].p;
			x=pre[x][i].id;
		}
	}
	return ans;
}
#ifndef ONLINE_JUDGE
int main()
{
	int n,q;
	scanf("%d%d",&n,&q);
	vector<int> v;
	for(int i=1;i<=n;i++)
	{
		int x;
		scanf("%d",&x);
		v.push_back(x);
	}
	init(v);
	for(int i=1;i<=q;i++)
	{
		int x,y;
		scanf("%d%d",&x,&y);
		printf("%lld\n",query(x,y));
	}
	return 0;
}
#endif
